import React from 'react'
import { Effect, pipe } from 'https://esm.sh/effect@3'

const program = pipe(
  Effect.succeed(21),
  Effect.map((n) => n * 2),
)

export default function App() {
  const result = Effect.runSync(program)
  return (
    <div style={{ fontFamily: 'system-ui', padding: 24, color: '#0f172a' }}>
      <h1>Effect basics</h1>
      <p>An Effect is a description. runSync executes it.</p>
      <p style={{ fontSize: 32, fontWeight: 700 }}>result = {result}</p>
    </div>
  )
}

